watermark-annotation-no-rotation-propert.code:
// CORRECT: Use TextStamp for rotated watermark (recommended for rotation)
using (Document pdfDoc = new Document(xslFoPath, loadOptions))
{
    Page page = pdfDoc.Pages[1];
    TextStamp stamp = new TextStamp("CONFIDENTIAL")
    {
        Opacity = 0.3,
        TextState = { FontSize = 24, ForegroundColor = Aspose.Pdf.Color.Gray }
    };
    stamp.Rotate = Rotation.on90; // or on180, on270, etc.
    stamp.HorizontalAlignment = HorizontalAlignment.Center;
    stamp.VerticalAlignment = VerticalAlignment.Center;
    stamp.Margin = new MarginInfo(0, 0, 0, 0);
    stamp.Position = new Aspose.Pdf.Rectangle(100, 400, 500, 600).Location;
    page.AddStamp(stamp);
    pdfDoc.Save(outputPdf);
}

// WRONG: Attempting to set Rotation on WatermarkAnnotation (not supported)
// WatermarkAnnotation watermark = new WatermarkAnnotation(page, rect)
// {
//     Rotation = 45 // ❌ CS0117: Rotation property does not exist
